import { signal } from '@preact/signals';
import { useCallback, useEffect } from 'preact/hooks';
import { getUserSelf } from 'service/user/resource';
import { isRegisteredViaPhone } from 'service/user/utils';
import { User } from 'signals/utils/user';
import { tld } from 'utils/env';
import { LocalStorage, LocalStorageKeys } from 'utils/LocalStorage';

export type UserLoginState = 'login' | 'logout' | 'forget' | 'uninitialized';
export interface UserEvent extends Event {
	detail: { uid: number | undefined; state: UserLoginState };
}
declare global {
	interface WindowEventMap {
		login: UserEvent;
		badge: UserEvent;
		logout: UserEvent;
		forget: UserEvent;
	}

	/**
	 * https://gitlab.seznam.net/rus/login/-/blob/master/src/static/js/api/3.1/src/user.ts
	 */
	type LoginState = 'login' | 'logout' | 'forget';

	/**
	 * https://gitlab.seznam.net/rus/login/-/blob/master/src/static/js/api/3.1/src/conf.ts
	 */
	type LoginCfg = Partial<{
		lang: string;
		log: (...args: any[]) => void;
		oauth: Partial<{
			client_id: string;
			redirect_uri: string;
			state: string;
		}>;
		popup: boolean;
		serviceId: string;
		source: string;
		sync: boolean;
		accountHost: string;
		ignoreRemoteSwitch: boolean;
		loginHost: string;
		messHost: string;
		notificationsHost: string;
		registerHost: string;
		serviceHost: string;
		switchUsers: boolean;
		uid: number | null;
	}>;

	interface LoginOptions {
		sourceComponent?: string;
	}

	interface Window {
		login: {
			version: string;
			cfg: (c: LoginCfg) => void;
			link: (a?: HTMLAnchorElement, options?: LoginOptions) => HTMLAnchorElement;
			open: (options?: LoginOptions | string | null, legacyUsername?: string) => globalThis.Window | null;
			close: () => void;
			register: {
				open: (options?: LoginOptions) => globalThis.Window | null;
				link: (a?: HTMLAnchorElement, options?: LoginOptions) => HTMLAnchorElement;
			};
			oauth: {
				open: () => globalThis.Window | null;
				link: (a?: HTMLAnchorElement) => HTMLAnchorElement;
			};
			assignEmail: {
				open: (options?: LoginOptions) => globalThis.Window | null;
				link: (a?: HTMLAnchorElement, loginOptions?: LoginOptions) => HTMLAnchorElement;
			};
			updateDialog: {
				show: () => Promise<void>;
			};
			autologin: () => boolean;
			socialToken: {
				get: () => Promise<string>;
			};
			current: {
				state: LoginState | null;
				uid: number | null;
				premium: boolean;
				/**
				 * Seznam bez reklam
				 */
				sbr: boolean;
				advert_uid: string | null;
				pid: string | null;
				adminName: string;
				others: {
					advert_uid: string;
					state: LoginState;
				}[];
				euconsent: string | null;
				encodedFlags: string;
			};
		};
	}
}

export const SOURCE_COMPONENT = {
	ADD_OFFER: 'add_offer',
	FAVORITES_ADD: 'favourites_add',
	MESSENGER_OPEN: 'messenger_open',
	MESSENGER_REOPEN: 'messenger_reopen',
	SAVED_SEARCH_ADD: 'saved_search_add',
	OFFER_SHOW_PHONE: 'offer_show_phone',
	OFFER_SEND_MESSAGE: 'offer_send_message',
} as const;

export type SourceComponent = (typeof SOURCE_COMPONENT)[keyof typeof SOURCE_COMPONENT];

let currentUser: User = new User(undefined, 'uninitialized');
if (globalThis?.window && globalThis.window.login) {
	const windowUser = globalThis.window.login.current;
	if (windowUser?.uid && windowUser?.state) {
		currentUser = new User(windowUser.uid, windowUser.state);
	}
}
export const user = signal<User>(currentUser);

export const isBadgeReady = signal(false);

export function useLoginCallback({
	localStorageKey,
	localStorageValue = 'true',
	badgeEventCallback,
}: {
	localStorageKey: LocalStorageKeys;
	localStorageValue?: string;
	badgeEventCallback: () => void;
}) {
	const initialized = signal(false);

	const handleBadge = useCallback(() => {
		if (LocalStorage.getItem(localStorageKey) === localStorageValue) {
			LocalStorage.removeItem(localStorageKey);
			badgeEventCallback();
		}
	}, [badgeEventCallback]);

	useEffect(() => {
		globalThis.window.addEventListener('badge', handleBadge);

		return () => {
			globalThis.window.removeEventListener('badge', handleBadge);
		};
	});

	if (!initialized.peek()) {
		initialized.value = true;
		handleBadge();
	}

	return {
		setLoginCallback: useCallback(
			() => LocalStorage.setItem(localStorageKey, localStorageValue),
			[localStorageKey, localStorageValue],
		),
	};
}

export type LoginOpenOptions = {
	isAssignEmail?: boolean;
	sourceComponent?: SourceComponent;
};

type LoginCallback = { callback: () => void; resetOnAccountSwitch?: boolean };

class LoginManager {
	private static instance: LoginManager;
	private loginRedirectUrl: string | undefined;
	private logoutRedirectUrl: string | undefined;
	private loginCallback: LoginCallback | undefined;
	private isAssignEmail: boolean = false;

	private constructor() {}

	static getInstance(): LoginManager {
		if (!LoginManager.instance) {
			LoginManager.instance = new LoginManager();
		}
		return LoginManager.instance;
	}

	public init() {
		this.configure();

		globalThis.window.addEventListener('login', this.handleLogin.bind(this));
		globalThis.window.addEventListener('badge', this.handleBadge.bind(this));
		globalThis.window.addEventListener('logout', this.handleLogout.bind(this));
		globalThis.window.addEventListener('forget', this.handleForget.bind(this));
		globalThis.window.addEventListener('login-close', this.handleLoginClose.bind(this));
	}

	public openLogin(
		options:
			| (LoginOpenOptions & { loginRedirectUrl?: string })
			| (LoginOpenOptions & { loginCallback?: LoginCallback }),
	) {
		if ('loginRedirectUrl' in options) {
			this.loginRedirectUrl = options.loginRedirectUrl;
		}

		if ('loginCallback' in options) {
			this.loginCallback = options.loginCallback;
		}

		const { login } = window;

		if (login) {
			const { isAssignEmail = false, sourceComponent } = options;
			const loginOptions: LoginOptions = { sourceComponent };
			this.isAssignEmail = isAssignEmail;

			const isOpen = isAssignEmail ? login.assignEmail.open(loginOptions) : login.open(loginOptions);

			if (!isOpen) {
				globalThis.window.location.href = isAssignEmail
					? login.assignEmail.link(undefined, loginOptions).href
					: login.link(undefined, loginOptions).href;
			}
		}
	}

	public setLogoutRedirectUrl(logoutRedirectUrl: string | undefined) {
		this.logoutRedirectUrl = logoutRedirectUrl;
	}

	public resetLogoutRedirectUrl() {
		this.setLogoutRedirectUrl(undefined);
	}

	private configure() {
		const loginCfg: LoginCfg = { serviceId: 'sbazar' };

		if (tld() === 'dev.dszn.cz') {
			// eslint-disable-next-line no-console
			loginCfg.log = console.log;
		}

		globalThis.window.login?.cfg(loginCfg);
	}

	private handleLogin(event: UserEvent) {
		if (user.value?.uid && user.value?.uid !== event.detail.uid && this.loginCallback?.resetOnAccountSwitch) {
			this.loginCallback = undefined;
		}

		this.executePostLoginActions();
	}

	private handleBadge(event: UserEvent) {
		user.value = new User(event.detail.uid, event.detail.state);
		isBadgeReady.value = true;
	}

	private handleLogout() {
		if (this.logoutRedirectUrl) {
			globalThis.window.location.href = this.logoutRedirectUrl;
		} else {
			globalThis.window.location.reload();
		}
	}

	private handleForget() {
		globalThis.window.location.reload();
	}

	private executePostLoginActions() {
		if (this.loginCallback) {
			this.loginCallback.callback();
			this.loginCallback = undefined;
		}

		if (this.loginRedirectUrl) {
			globalThis.window.location.href = this.loginRedirectUrl;
			this.loginRedirectUrl = undefined;
			return;
		}

		globalThis.window.location.reload();
	}

	private async handleLoginClose() {
		if (this.isAssignEmail) {
			try {
				const userData = await getUserSelf({ use_cache: false });
				if (userData && !isRegisteredViaPhone(userData)) {
					this.executePostLoginActions();
				}
			} catch {
				window.location.reload();
			}

			this.isAssignEmail = false;
		}

		this.loginCallback = undefined;
		this.loginRedirectUrl = undefined;
	}
}

if (globalThis?.window) {
	LoginManager.getInstance().init();
}

export const loginManager = LoginManager.getInstance();
