import type { UserLoginState } from 'signals/login';
import { getUserSelf } from 'service/user/resource';
import { type UserData } from 'service/user/model';

export class User {
	private promise: Promise<UserData> | null = null;

	constructor(
		public uid: number | undefined = undefined,
		public state: UserLoginState = 'uninitialized',
	) {}

	getUserData() {
		if (this.state !== 'login') return null;
		if (!this.promise) {
			this.promise = getUserSelf().catch(null);
		}

		return this.promise;
	}
}
